try {
const raw = $('Twilio Trigger').first().json;

const isCloudEvents = !!raw.specversion;

// Use $now as reliable fallback for Format 1 (no timestamp available)
// For Format 2, use the actual event time for accuracy
const time = isCloudEvents 
  ? raw.time 
  : $now.toISO();   // ← $now = exact moment Twilio Trigger fired

const body       = isCloudEvents ? raw.data?.body       : raw.Body       || "";
const from       = isCloudEvents ? raw.data?.from       : raw.From       || "";
const to         = isCloudEvents ? raw.data?.to         : raw.To         || "";
const accountSid = isCloudEvents ? raw.data?.accountSid : raw.AccountSid || "";
const messageSid = isCloudEvents ? raw.data?.messageSid : raw.MessageSid || "";

const inputDate = new Date(time);
const dayOfWeek = inputDate.toString() !== 'Invalid Date'
  ? ["Sunday","Monday","Tuesday","Wednesday","Thursday","Friday","Saturday"][inputDate.getUTCDay()]
  : "Unknown";

return [{
  json: {
    ...raw,
    dayOfWeek,
    normalized: {
      time,
      body,
      from,
      to,
      accountSid,
      messageSid,
      isCloudEvents
    }
  }
}];

} catch(e) {
  return [{ json: { error: e.message, node: "Code4" } }];
}

try {
// --- Step 1: Separate all incoming data by its 'Source' field ---
const allItems = $input.all();

const employees = allItems.filter(item => item.json.Source === 'employees');
const preferences = allItems.filter(item => item.json.Source === 'preferences');
const locations = allItems.filter(item => item.json.Source === 'locations');
const shifts = allItems.filter(item => item.json.Source === 'shift');

// --- Step 2: Restructure the data ---
// We loop through each employee and attach their related information.
const output = employees.map(employeeItem => {
  const employeeId = employeeItem.json.id;

  // Link Preferences based on 'Employee ID' field
  const relatedPreferences = preferences
    .filter(prefItem => (prefItem.json['Employee ID'] || []).includes(employeeId))
    .map(item => item.json);

  // Link Shifts based on 'Employee Shift' field
  const employeeShiftIds = employeeItem.json['Employee Shift'] || [];
  const relatedShifts = shifts
    .filter(shiftItem => employeeShiftIds.includes(shiftItem.json.id))
    .map(item => item.json);

  // Link Locations based on 'Location ID' field
  const employeeLocationIds = employeeItem.json['Location ID'] || [];
  const relatedLocations = locations
    .filter(locationItem => employeeLocationIds.includes(locationItem.json.id))
    .map(item => item.json);

  // --- Step 3: Build the final, flattened output object ---
  // The employee's data is now spread into the top level of the object,
  // removing the extra "employee" wrapper.
  return {
    json: {
      ...employeeItem.json,
      preferences: relatedPreferences,
      shifts: relatedShifts,
      locations: relatedLocations
    }
  };
});

// --- Step 4: Return the final, structured data ---
return output;


} catch(e) {
  return [{ json: { error: e.message, node: "Code2" } }];
}

try {
// --- Step 1: Get Target Shift Information ---

// Get the details of the location/post that needs to be filled from the 'Get a record4' node.
const targetLocationData = $('Get a record4').first().json;
// Get the original calling-off worker's record to find out which shift needs covering.
const originalWorker = $('Search records10').first().json;

// If critical data is missing, exit gracefully by returning the original unsorted list.
if (!targetLocationData || !originalWorker) {
  return $input.all();
}

// Extract the specific requirements of the shift that needs coverage.
const targetLocationId = targetLocationData.id;
// Assumes the first shift linked to the calling-off worker is the one to be replaced.
const targetShiftId = (originalWorker['Employee Shift'] || [])[0];
// This is the post requirement, e.g., ["Inside"] or ["Outside", "Requires First Aid"]
const targetPostRequirements = targetLocationData['Post Requirements'] || [];


// --- Step 2: Score Each Employee Based on Preferences ---

// Get the list of potential replacement employees from the previous node.
const potentialReplacements = $input.all();

const scoredEmployees = potentialReplacements.map(item => {
  const employee = item.json;
  let score = 0;

  // The 'preferences' object was attached in the 'Code2' node.
  // It's an array of preference records from Airtable for this employee.
  const preferences = employee.preferences || [];
  console.log(employee.preferences)
  console.log(employee.name)
  console.log(employee)

  // Loop through each preference record to calculate a score.
  for (const pref of preferences) {
    // --- Location Preference Check (Score: 4) ---
    // NOTE: Assumes your preference table field is named 'Preferred Locations (from Locations)'
    if (pref['Preference Type'] === 'Location') {
      const preferredLocationIds = pref['Location Detail'] || [];
      console.log(preferredLocationIds,targetLocationId)
      if (preferredLocationIds.includes(targetLocationId)) {
        score += 4;
      }
    }

    // --- Shift Preference Check (Score: 3) ---
    // NOTE: Assumes your preference table field is named 'Preferred Shifts (from Employee Shift)'
    if (pref['Preference Type'] === 'Shift') {
      const preferredShiftIds = pref['Preferred Shifts (from Employee Shift)'] || [];
      if (targetShiftId && preferredShiftIds.includes(targetShiftId)) {
        score += 3;
      }
    }

    // --- Post Requirement Preference Check (Score: 2) ---
    // NOTE: Assumes your preference table field is named 'Preferred Post Type'
    if (pref['Preference Type'] === 'Post') {
       const preferredPostTypes = pref['Preferred Post Type'] || [];
      console.log("prefs")// e.g., ["Inside", "Outside"]
       // Checks if any of the employee's preferred post types match any of the target shift's requirements.
       const hasMatch = targetPostRequirements.some(req => preferredPostTypes.includes(req));
       if (hasMatch) {
         score += 2;
       }
    }
  }

  // Add the final calculated score to the employee's data.
  item.json.priorityScore = score;
  return item;
});


// --- Step 3: Sort Employees by Score ---

// Sort the list of employees in descending order based on their new score.
// Employees with a higher score (better match) will appear at the top.
const sortedEmployees = scoredEmployees.sort((a, b) => {
  return (b.json.priorityScore || 0) - (a.json.priorityScore || 0);
});

return sortedEmployees;
} catch(e) {
  return [{ json: { error: e.message, node: "Preference Based : Sorting" } }];
}

try {
// --- Step 1: Get the list of potential replacement candidates ---
// This is the list of employees who have passed all previous filters (availability, conflicts, etc.).
// We get this from the 'Code3' node, which is the last step before this training check.
const potentialReplacements = $('Filter 4: Employee-to-Employee Compatibility').all();

// --- Step 2: Check if any special training is required for this post ---
// 'Get a record4' holds the data for the location/post that needs covering.
// We check if the "Special Training Requirements" field has any entries.
const locationData = $('Get a record4').first().json;
const isTrainingRequired = Array.isArray(locationData['Special Training Requirements']) && locationData['Special Training Requirements'].length > 0;

// If no special training is required, we don't need to filter.
// Return the full list of potential replacements immediately.
if (!isTrainingRequired) {
  return potentialReplacements;
}

// --- Step 3: Get the list of employees who have the required training ---
// The input to this Code node ($input) comes from 'Search records3',
// which found all the training records for the required training.
const trainedEmployeeRecords = $input.all();

// Create a Set of qualified employee IDs for efficient lookup.
// The 'Employee ID' field in the 'Employee Trainings' table is a lookup/linked field, so it's an array.
const qualifiedEmployeeIds = new Set();
for (const record of trainedEmployeeRecords) {
  if (Array.isArray(record.json['Employee ID'])) {
    for (const id of record.json['Employee ID']) {
      qualifiedEmployeeIds.add(id);
    }
  }
}

// --- Step 4: Filter the potential replacements ---
// Keep only the employees whose ID is in our set of qualified employee IDs.
const finalQualifiedReplacements = potentialReplacements.filter(item => {
  const employeeId = item.json.id; // The record ID of the employee in the Employees table.
  return qualifiedEmployeeIds.has(employeeId);
});

// --- Step 5: Return the final, filtered list ---
// This list now contains only employees who are available, not in conflict, AND have the special training.
return finalQualifiedReplacements;
} catch(e) {
  return [{ json: { error: e.message, node: "Filter 3: Post Compatibility(Training Requirements)" } }];
}

