// Helper to safely pick a field from either {fields:{}} shape or flat JSON
function getField(obj, key) {
  if (!obj) return undefined;
  if (obj.fields && Object.prototype.hasOwnProperty.call(obj.fields, key)) {
    return obj.fields[key];
  }
  return obj[key];
}

// 1) Read "Search records4" results (adjust node name if needed)
let srcItems = $('Search records4').all(); // full items (json + pairedItem)
const records = srcItems.map(i => i.json);
const workingEmployeesIds = $('Search records11').all().map(e=> e.json.Employee[0]);
// 2) Build conflict list from BOTH Employee 1 Name and Employee 2 Name
const conflictSet = new Set();
// filter only employee those are working in that shift
srcItems = srcItems.filter(e=> workingEmployeesIds.includes(e["Employee 1 ID"]) || workingEmployeesIds.includes(e["Employee 2 ID"]));


for (const rec of records) {
  // Read possible arrays (e.g., lookup/rollup or multi‑value)
  const emp1 = getField(rec, 'Employee 1 Name');
  const emp2 = getField(rec, 'Employee 2 Name');

  // Normalize helper: push all truthy string values
  const pushValues = (val) => {
    if (Array.isArray(val)) {
      for (const v of val) {
        if (v) conflictSet.add(String(v).trim());
      }
    } else if (val) {
      conflictSet.add(String(val).trim());
    }
  };

  pushValues(emp1);
  pushValues(emp2);
}

// OPTIONAL: case‑insensitive compare
