const employeeRecord = $('Search records10').first();
if (!employeeRecord) return [{ json: { id: null, noShiftFound: true, reason: 'No employee record found' } }];

const employeeId = employeeRecord.json.id;
const formatter = new Intl.DateTimeFormat('en-GB', {
  timeZone: 'America/Los_Angeles',
  year: 'numeric', month: '2-digit', day: '2-digit'
});
const leaveDateStr = formatter.format(new Date());

const allShifts = $input.all();
const todaysShift = allShifts.filter(item => {
  const shift = item.json;
  const employeeMatch = Array.isArray(shift.Employee) && shift.Employee.includes(employeeId);
  if (!employeeMatch) return false;
  const shiftStartDate = new Date(shift.Start);
  const shiftDateStr = formatter.format(shiftStartDate);
  return shiftDateStr === leaveDateStr;
});

if (todaysShift.length === 0) return [{ json: { id: null, noShiftFound: true, reason: 'No shift scheduled for today' } }];

return todaysShift.map(item => {
  const shift = item.json;

  const startDate = shift.Start ? new Date(shift.Start) : null;
  const endDate   = shift.End   ? new Date(shift.End)   : null;

  const timeFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Los_Angeles',
    hour: '2-digit', minute: '2-digit', hour12: true
  });
  const dateFormatter = new Intl.DateTimeFormat('en-US', {
    timeZone: 'America/Los_Angeles',
    month: '2-digit', day: '2-digit', year: 'numeric'
  });

  return {
    json: {
      ...shift,
      noShiftFound: false,
      shiftDetails: {
        id:            shift.id       ?? null,
        Start:         shift.Start    ?? null,
        End:           shift.End      ?? null,
        Hours:         shift.Hours    ?? null,
        Location:      shift.Location ?? null,
        Status:        shift.Status   ?? null,
        Employee:      shift.Employee ?? null,
        startFormatted: startDate ? dateFormatter.format(startDate) + ' ' + timeFormatter.format(startDate) : null,
        endFormatted:   endDate   ? dateFormatter.format(endDate)   + ' ' + timeFormatter.format(endDate)   : null,
        dateOnly:       startDate ? dateFormatter.format(startDate) : null,
        startTimeOnly:  startDate ? timeFormatter.format(startDate) : null,
        endTimeOnly:    endDate   ? timeFormatter.format(endDate)   : null,
      }
    },
    pairedItem: item.pairedItem
  };
});

try {
// Get input data
const inputData = $input.all();

// Get target shift
const targetShift = $('Code in JavaScript1').first().json;
const targetShiftStart = targetShift?.Start ? new Date(targetShift.Start) : null;
const targetShiftEnd = targetShift?.End ? new Date(targetShift.End) : null;

if (!targetShiftStart || !targetShiftEnd) {
    return inputData;
}

// Day names for checking
const dayNames = ["Sunday", "Monday", "Tuesday", "Wednesday", "Thursday", "Friday", "Saturday"];
const targetDayName = dayNames[targetShiftStart.getDay()];

// Extract time
const targetStartHour = targetShiftStart.getHours();
const targetStartMinute = targetShiftStart.getMinutes();
const targetStartTime = `${targetStartHour.toString().padStart(2, '0')}:${targetStartMinute.toString().padStart(2, '0')}`;

const results = [];

for (const item of inputData) {
    const employee = item.json;

    // SIMPLIFIED AVAILABILITY CHECK:
    // Since we don't have actual availability data in this node's input,
    // we'll check for common indicators

    // Check 1: Look for any scheduling conflicts
    // Get employee's existing shifts
    const employeeShifts = employee.shifts || [];

    let hasConflict = false;
    let conflictReason = "";

    // Check if employee already has a shift at this time
    for (const shift of employeeShifts) {
        if (shift.Start && shift.End) {
            const shiftStart = new Date(shift.Start);
            const shiftEnd = new Date(shift.End);

            // Check if shift overlaps with target shift
            if (targetShiftStart < shiftEnd && targetShiftEnd > shiftStart) {
                hasConflict = true;
                conflictReason = `Already has shift: ${shift.Start} - ${shift.End}`;
                break;
            }
        }
    }

    // Check 2: Look for any "unavailable" indicators in employee data
    // Check various fields that might indicate unavailability
    let isMarkedUnavailable = false;

    // Check Notes or other fields for unavailability
    if (employee.Notes && employee.Notes.toLowerCase().includes("not available")) {
        isMarkedUnavailable = true;
    }

    // Check Employment Status
    if (employee["Employment Status"] && employee["Employment Status"].toLowerCase() !== "active") {
        isMarkedUnavailable = true;
    }

    // Final availability determination
    const isAvailable = !hasConflict && !isMarkedUnavailable;

    results.push({
        json: {
            ...employee,
            isAvailable: isAvailable,
            availabilityDetails: {
                targetDay: targetDayName,
                targetTime: targetStartTime,
                hasConflict: hasConflict,
                conflictReason: conflictReason,
                isMarkedUnavailable: isMarkedUnavailable,
                existingShiftsCount: employeeShifts.length,
                checkDate: new Date().toISOString()
            }
        }
    });
}

// Return only available employees
return results.filter(item => item.json.isAvailable);
} catch(e) {
  return [{ json: { error: e.message, node: "Filter 5 (Availability Restrictions): Time Based" } }];
}
